import React, { useState, useRef, useEffect } from 'react';
import { useAuth } from '../contexts/AuthContext';
import { Card, Form, Button, ProgressBar, Badge, Alert } from 'react-bootstrap';
import { Upload, File, X, CheckCircle } from 'lucide-react';
import { toast } from 'react-toastify';
import { uploadDocument, getEmployees, getCategories } from '../api';
import './DocumentUpload.css';

const DocumentUpload = () => {
  const [formData, setFormData] = useState({
    employeeId: '',
    employeeName: '',
    store: '',
    issueDate: '',
    expiryDate: '',
    remarks: ''
  });
  const [files, setFiles] = useState([]); // Now stores {file: File, documentType: string}
  const [uploadProgress, setUploadProgress] = useState(0);
  const [isUploading, setIsUploading] = useState(false);
  const [dragActive, setDragActive] = useState(false);
  const [employees, setEmployees] = useState([]);
  const [documentTypes, setDocumentTypes] = useState([]);
  const [uploadResults, setUploadResults] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [errors, setErrors] = useState({});
  const fileInputRef = useRef(null);
  const { user } = useAuth();

  useEffect(() => {
    loadEmployees();
    loadCategories();
    // Auto-fill today's date for issue date
    const today = new Date();
    const todayString = today.toISOString().split('T')[0];
    setFormData(prev => ({
      ...prev,
      issueDate: todayString
    }));
  }, []);

  const loadEmployees = async () => {
    try {
      const response = await getEmployees();
      if (response.data && response.data.data) {
        setEmployees(response.data.data);
      }
    } catch (error) {
      console.error('Error loading employees:', error);
      toast.error('Error loading employees', {
        position: 'top-right',
        autoClose: 3000
      });
    }
  };

  const loadCategories = async () => {
    try {
      const response = await getCategories();
      if (response.data && response.data.data) {
        setDocumentTypes(response.data.data.map(cat => cat.name));
      }
    } catch (error) {
      console.error('Error loading categories:', error);
      setDocumentTypes([
        'ID Proof',
        'Driving License',
        'Medical Certificate',
        'Training Certificate',
        'Employment Contract',
        'Educational Certificate',
        'Address Proof',
        'Police Verification'
      ]);
    }
  };

  const stores = [
    'Store 1', 'Store 2', 'Store 3', 'Store 4', 'Store 5',
    'Store 6', 'Store 7', 'Store 8', 'Store 9', 'Store 10'
  ];

  const getTodayDate = () => {
    const today = new Date();
    return today.toISOString().split('T')[0];
  };

  const getMinExpiryDate = () => {
    if (!formData.issueDate) {
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      return tomorrow.toISOString().split('T')[0];
    }
    
    const issueDate = new Date(formData.issueDate);
    issueDate.setDate(issueDate.getDate() + 1);
    return issueDate.toISOString().split('T')[0];
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    // Clear error for this field
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }));
    }
    
    // Changed: Select by employee name, auto-fill employee ID
    if (name === 'employeeName' && value) {
      const selectedEmployee = employees.find(emp => emp.name === value);
      if (selectedEmployee) {
        setFormData(prev => ({
          ...prev,
          employeeName: value,
          employeeId: selectedEmployee.id,
          store: selectedEmployee.store || prev.store
        }));
        return;
      }
    }
    
    if (name === 'issueDate') {
      setFormData(prev => {
        const newFormData = {
          ...prev,
          issueDate: value
        };
        
        if (prev.expiryDate && value) {
          const issueDate = new Date(value);
          const expiryDate = new Date(prev.expiryDate);
          if (expiryDate <= issueDate) {
            newFormData.expiryDate = '';
            toast.warning('Expiry date must be after issue date. Please select a new expiry date.', {
              position: 'top-right',
              autoClose: 3000
            });
          }
        }
        
        return newFormData;
      });
      return;
    }
    
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleDrag = (e) => {
    e.preventDefault();
    e.stopPropagation();
    if (e.type === 'dragenter' || e.type === 'dragover') {
      setDragActive(true);
    } else if (e.type === 'dragleave') {
      setDragActive(false);
    }
  };

  const handleDrop = (e) => {
    e.preventDefault();
    e.stopPropagation();
    setDragActive(false);

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      handleFileSelect(e.dataTransfer.files);
    }
  };

  const handleFileSelect = (selectedFiles) => {
    const fileArray = Array.from(selectedFiles);
    const validTypes = ['application/pdf', 'image/jpeg', 'image/png', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'];
    
    const validFiles = fileArray.filter(file => {
      if (validTypes.includes(file.type)) {
        return true;
      } else {
        toast.error(`Invalid file type: ${file.name}. Please upload PDF, DOCX, JPG, or PNG`, {
          position: 'top-right',
          autoClose: 3000
        });
        return false;
      }
    });
    
    // Changed: Store files with document type
    const newFiles = validFiles.map(file => ({
      file: file,
      documentType: '' // Empty initially, user must select
    }));
    
    setFiles(prev => [...prev, ...newFiles]);
    
    // Clear file error if files are selected
    if (validFiles.length > 0 && errors.files) {
      setErrors(prev => ({
        ...prev,
        files: ''
      }));
    }
  };

  const handleFileInput = (e) => {
    if (e.target.files && e.target.files.length > 0) {
      handleFileSelect(e.target.files);
      e.target.value = '';
    }
  };

  const removeFile = (index) => {
    setFiles(prev => prev.filter((_, i) => i !== index));
  };

  // New: Handle document type change for specific file
  const handleFileDocumentTypeChange = (index, documentType) => {
    setFiles(prev => {
      const newFiles = [...prev];
      newFiles[index] = {
        ...newFiles[index],
        documentType: documentType
      };
      return newFiles;
    });

    // Clear error for this file if document type is selected
    if (errors[`file_${index}_documentType`]) {
      setErrors(prev => ({
        ...prev,
        [`file_${index}_documentType`]: ''
      }));
    }
  };

  const validateForm = () => {
    const newErrors = {};
    
    if (!formData.employeeName) {
      newErrors.employeeName = 'Please select an employee';
    }
    
    if (!formData.employeeId) {
      newErrors.employeeId = 'Employee ID is required';
    }
    
    if (!formData.store) {
      newErrors.store = 'Please select a store';
    }
    
    if (!formData.issueDate) {
      newErrors.issueDate = 'Issue date is required';
    }
    
    if (!formData.expiryDate) {
      newErrors.expiryDate = 'Expiry date is required';
    } else if (formData.issueDate && new Date(formData.expiryDate) <= new Date(formData.issueDate)) {
      newErrors.expiryDate = 'Expiry date must be after issue date';
    }
    
    if (files.length === 0) {
      newErrors.files = 'Please select at least one file to upload';
    } else {
      // Validate each file has a document type
      files.forEach((fileObj, index) => {
        if (!fileObj.documentType) {
          newErrors[`file_${index}_documentType`] = 'Document type is required';
          newErrors.files = 'Please select document type for all files';
        }
      });
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    
    if (!validateForm()) {
      toast.error('Please fill all required fields correctly', {
        position: 'top-right',
        autoClose: 3000
      });
      return;
    }

    setIsUploading(true);
    setUploadProgress(0);
    setShowResults(false);
    setUploadResults([]);

    try {
      const results = [];
      const totalFiles = files.length;
      
      // Upload each file with its own document type
      for (let i = 0; i < files.length; i++) {
        const fileObj = files[i];
        const fileFormData = new FormData();
        
        fileFormData.append('employeeId', formData.employeeId);
        fileFormData.append('employeeName', formData.employeeName);
        fileFormData.append('store', formData.store);
        fileFormData.append('documentType', fileObj.documentType); // Individual document type
        fileFormData.append('issueDate', formData.issueDate);
        fileFormData.append('expiryDate', formData.expiryDate);
        fileFormData.append('remarks', formData.remarks || 'N/A');
        fileFormData.append('document', fileObj.file);
        fileFormData.append('uploadedBy', user?.name || 'HR User');

        try {
          const response = await uploadDocument(fileFormData);
          results.push({
            fileName: fileObj.file.name,
            documentType: fileObj.documentType,
            success: true,
            message: 'Uploaded successfully'
          });
        } catch (error) {
          results.push({
            fileName: fileObj.file.name,
            documentType: fileObj.documentType,
            success: false,
            message: error.response?.data?.message || 'Upload failed'
          });
        }

        // Update progress
        const progress = Math.round(((i + 1) / totalFiles) * 100);
        setUploadProgress(progress);
      }

      setUploadResults(results);
      setShowResults(true);

      const successCount = results.filter(r => r.success).length;
      const failureCount = results.filter(r => !r.success).length;

      if (successCount > 0 && failureCount === 0) {
        toast.success(`Successfully uploaded ${successCount} document(s)!`, {
          position: 'top-right',
          autoClose: 3000
        });
        
        // Reset form
        setFormData({
          employeeId: '',
          employeeName: '',
          store: '',
          issueDate: getTodayDate(),
          expiryDate: '',
          remarks: ''
        });
        setFiles([]);
        setErrors({});
      } else if (successCount > 0 && failureCount > 0) {
        toast.warning(`Uploaded ${successCount} document(s). ${failureCount} failed.`, {
          position: 'top-right',
          autoClose: 4000
        });
      } else {
        toast.error('All uploads failed. Please try again.', {
          position: 'top-right',
          autoClose: 3000
        });
      }

    } catch (error) {
      console.error('Upload error:', error);
      toast.error('Error uploading documents. Please try again.', {
        position: 'top-right',
        autoClose: 3000
      });
    } finally {
      setIsUploading(false);
      setUploadProgress(0);
    }
  };

  const formatFileSize = (bytes) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(2) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(2) + ' MB';
  };

  return (
    <div className="document-upload">
      <Card className="upload-card">
        <Card.Header className="card-header-custom">
          <h3 className="mb-0">
            <Upload size={24} className="me-2" />
            Upload Employee Documents
          </h3>
        </Card.Header>
        <Card.Body>
          {showResults && uploadResults.length > 0 && (
            <Alert 
              variant={uploadResults.every(r => r.success) ? 'success' : 'warning'} 
              dismissible 
              onClose={() => setShowResults(false)}
              className="upload-results mb-4"
            >
              <div className="fw-bold mb-2">
                Upload Results: {uploadResults.filter(r => r.success).length} succeeded, {uploadResults.filter(r => !r.success).length} failed
              </div>
              <ul className="mb-0">
                {uploadResults.map((result, index) => (
                  <li key={index}>
                    <CheckCircle 
                      size={16} 
                      className={`me-1 ${result.success ? 'text-success' : 'text-danger'}`} 
                    />
                    <strong>{result.fileName}</strong> ({result.documentType}): {result.message}
                  </li>
                ))}
              </ul>
            </Alert>
          )}

          <Form onSubmit={handleSubmit}>
            <div className="row">
              {/* Changed: Employee Name first */}
              <div className="col-md-6 mb-3">
                <Form.Label>Employee <span className="text-danger">*</span></Form.Label>
                <Form.Select
                  name="employeeName"
                  value={formData.employeeName}
                  onChange={handleInputChange}
                  required
                  isInvalid={!!errors.employeeName}
                >
                  <option value="">Select Employee</option>
                  {employees.map(emp => (
                    <option key={emp.id} value={emp.name}>
                      {emp.name} - {emp.id} ({emp.store})
                    </option>
                  ))}
                </Form.Select>
                {errors.employeeName ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.employeeName}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    Select an employee from the list
                  </Form.Text>
                )}
              </div>

              {/* Employee ID - Auto-filled */}
              <div className="col-md-6 mb-3">
                <Form.Label>Employee ID <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="text"
                  name="employeeId"
                  value={formData.employeeId}
                  onChange={handleInputChange}
                  placeholder="Auto-filled when employee is selected"
                  required
                  readOnly
                  style={{ backgroundColor: '#f8f9fa' }}
                  isInvalid={!!errors.employeeId}
                />
                {errors.employeeId && (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.employeeId}
                  </Form.Control.Feedback>
                )}
              </div>

              <div className="col-md-6 mb-3">
                <Form.Label>Store <span className="text-danger">*</span></Form.Label>
                <Form.Select
                  name="store"
                  value={formData.store}
                  onChange={handleInputChange}
                  required
                  isInvalid={!!errors.store}
                >
                  <option value="">Select Store</option>
                  {stores.map(store => (
                    <option key={store} value={store}>{store}</option>
                  ))}
                </Form.Select>
                {errors.store && (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.store}
                  </Form.Control.Feedback>
                )}
              </div>

              <div className="col-md-6 mb-3">
                <Form.Label>Issue Date <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="date"
                  name="issueDate"
                  value={formData.issueDate}
                  onChange={handleInputChange}
                  max={getTodayDate()}
                  required
                  isInvalid={!!errors.issueDate}
                />
                {errors.issueDate ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.issueDate}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    Auto-filled with today's date
                  </Form.Text>
                )}
              </div>

              <div className="col-md-6 mb-3">
                <Form.Label>Expiry Date <span className="text-danger">*</span></Form.Label>
                <Form.Control
                  type="date"
                  name="expiryDate"
                  value={formData.expiryDate}
                  onChange={handleInputChange}
                  min={getMinExpiryDate()}
                  disabled={!formData.issueDate}
                  required
                  isInvalid={!!errors.expiryDate}
                />
                {errors.expiryDate ? (
                  <Form.Control.Feedback type="invalid" style={{ display: 'block' }}>
                    {errors.expiryDate}
                  </Form.Control.Feedback>
                ) : (
                  <Form.Text className="text-muted">
                    {formData.issueDate 
                      ? 'Must be after issue date' 
                      : 'Please select issue date first'}
                  </Form.Text>
                )}
              </div>

              <div className="col-md-12 mb-3">
                <Form.Label>Remarks</Form.Label>
                <Form.Control
                  as="textarea"
                  rows={3}
                  name="remarks"
                  value={formData.remarks}
                  onChange={handleInputChange}
                  placeholder="Enter any additional remarks or notes about these documents"
                />
              </div>
            </div>

            <div className="mb-4">
              <Form.Label>
                Upload Document(s) <span className="text-danger">*</span>
                {files.length > 0 && (
                  <Badge bg="primary" className="ms-2">{files.length} file(s) selected</Badge>
                )}
              </Form.Label>
              <div
                className={`drag-drop-area ${dragActive ? 'drag-active' : ''} ${files.length > 0 ? 'has-file' : ''} ${errors.files ? 'is-invalid' : ''}`}
                onDragEnter={handleDrag}
                onDragLeave={handleDrag}
                onDragOver={handleDrag}
                onDrop={handleDrop}
                onClick={() => fileInputRef.current?.click()}
              >
                <input
                  ref={fileInputRef}
                  type="file"
                  onChange={handleFileInput}
                  accept=".pdf,.docx,.jpg,.jpeg,.png"
                  multiple
                  className="d-none"
                />
                {files.length > 0 ? (
                  <div className="files-list">
                    {files.map((fileObj, index) => (
                      <div key={index} className="file-item-container mb-3">
                        <div className="file-preview-item">
                          <File size={20} className="text-primary me-2" />
                          <div className="flex-grow-1">
                            <div className="d-flex align-items-center justify-content-between mb-2">
                              <div>
                                <span className="file-name">{fileObj.file.name}</span>
                                <span className="file-size ms-2">
                                  ({formatFileSize(fileObj.file.size)})
                                </span>
                              </div>
                              <Button
                                variant="link"
                                size="sm"
                                onClick={(e) => {
                                  e.stopPropagation();
                                  removeFile(index);
                                }}
                                className="remove-file-btn"
                              >
                                <X size={16} />
                              </Button>
                            </div>
                            {/* Individual Document Type Selection */}
                            <Form.Select
                              size="sm"
                              value={fileObj.documentType}
                              onChange={(e) => {
                                e.stopPropagation();
                                handleFileDocumentTypeChange(index, e.target.value);
                              }}
                              onClick={(e) => e.stopPropagation()}
                              isInvalid={!!errors[`file_${index}_documentType`]}
                              className="document-type-select"
                            >
                              <option value="">Select Document Type</option>
                              {documentTypes.map(type => (
                                <option key={type} value={type}>{type}</option>
                              ))}
                            </Form.Select>
                            {errors[`file_${index}_documentType`] && (
                              <div className="text-danger small mt-1">
                                {errors[`file_${index}_documentType`]}
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                    <Button
                      variant="outline-primary"
                      size="sm"
                      onClick={(e) => {
                        e.stopPropagation();
                        fileInputRef.current?.click();
                      }}
                      className="mt-2"
                    >
                      <Upload size={16} className="me-1" />
                      Add More Files
                    </Button>
                  </div>
                ) : (
                  <div className="drag-drop-content">
                    <Upload size={48} className="text-muted mb-3" />
                    <p className="mb-1">Click to upload or drag and drop</p>
                    <p className="text-muted small">PDF, DOCX, JPG, PNG (Max 10MB per file) - Multiple files supported</p>
                  </div>
                )}
              </div>
              {errors.files && (
                <div className="text-danger small mt-1">{errors.files}</div>
              )}
            </div>

            {isUploading && (
              <div className="mb-4">
                <div className="d-flex justify-content-between mb-2">
                  <span>Uploading {files.length} file(s)...</span>
                  <span>{uploadProgress}%</span>
                </div>
                <ProgressBar now={uploadProgress} animated striped variant="primary" />
              </div>
            )}

            <Button
              type="submit"
              variant="primary"
              size="lg"
              className="w-100 upload-submit-btn"
              disabled={isUploading}
            >
              {isUploading ? `Uploading...` : `Upload Document${files.length !== 1 ? 's' : ''}`}
            </Button>
          </Form>
        </Card.Body>
      </Card>
    </div>
  );
};

export default DocumentUpload;
